import React from 'react';

function Header() {
  return (
    <header className="header">
      <div className="header-content">
        <h1>
          <span className="highlight">Sid</span>Bloom
        </h1>
        <p className="subtitle">Where every petal tells a story</p>
      </div>
    </header>
  );
}

export default Header;
